pub struct BitmapFont {
    pub data: &'static [u8],
    pub width: usize,
    pub height: usize,
    pub lochar: usize,
    pub hichar: usize,
    pub bytes_per_char: usize
}

impl BitmapFont {
    pub fn new(data: &'static [u8], width_px: usize, height_px: usize,
               lochar: usize, hichar: usize, bytes_per_char: usize) -> Self {
        Self {
            data,
            width: width_px,
            height: height_px, lochar, hichar, bytes_per_char
        }
    }

    pub fn null_font() -> Self {
        Self {
            data: &[],
            width: 0,
            height: 0,
            lochar: 0,
            hichar: 0,
            bytes_per_char: 0,
        }
    }
}

